﻿using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personMeta = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personMeta.Type.Name}");
Console.WriteLine($"  Kind = {personMeta.Kind}");
Console.WriteLine($"  Properties: {string.Join(", ", personMeta.Properties.Select(p => p.Name))}");

// 2) Probe without throwing: TryGetTypeInfo returns false if unavailable
//    Use a resolver that only handles Person — Stream will be "unknown".
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Artificially reject everything that isn't Person
            if (ti.Type != typeof(Person))
                ti.Kind = JsonTypeInfoKind.None;  // make it unusable
        })
};

// For a clean probe, use a resolver that simply doesn't produce metadata
// for the type. We'll create one from scratch:
var selectiveResolver = JsonTypeInfoResolver.Combine(
    new PersonOnlyResolver()
);
var probeOptions = new JsonSerializerOptions { TypeInfoResolver = selectiveResolver };

bool havePerson = probeOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? foundPerson);
bool haveStream = probeOptions.TryGetTypeInfo(typeof(Stream), out JsonTypeInfo? foundStream);

Console.WriteLine();
Console.WriteLine($"TryGetTypeInfo(Person) → {havePerson} (info: {foundPerson?.Type.Name ?? "null"})");
Console.WriteLine($"TryGetTypeInfo(Stream) → {haveStream} (info: {foundStream?.Type.Name ?? "null"})");

// --- Types ---------------------------------------------------------------

public record Person(string FirstName, string LastName, int Age);

/// A resolver that only provides metadata for Person.
file sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null; // signals "I don't handle this type"
    }
}

